def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        multiplier = 1 + (np.sin(item) + np.cos(bin_cap)) / 4
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    priority += val * np.cos(ratio * b / (a + 1)) * multiplier
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.sin(ratio * p * 1.1) / (q + 0.4)
                    priority += np.tanh(term) * 1.5 * multiplier
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 2.5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.1)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            priority *= multiplier
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 13):
                s += ((2 - ratio) ** n) / (n ** 2 + 0.6)
            if bin_cap < item * 1.15:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.06))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / m
            priority *= multiplier * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
            priority *= multiplier
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 3.5) * np.cos(k * ratio * 2.3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
            priority *= multiplier * 0.9
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 2.5 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
            priority *= multiplier * 1.05
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            sign = 1 if (i + idx) % 4 == 0 else -1
            priority += sign * np.sin(ratio * (i + idx)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if i % 2 == 0 and bin_cap % 2 == 1:
            priority *= 1.2
        elif i % 5 == 0:
            priority /= 1.3
        priorities[i] = priority
    return priorities
